#include <stdio.h>
#include <string.h>
#define MAXN 100

int isPalindrome(char *s, int l, int r) {
    while (l < r) {
        if (s[l] != s[r]) return 0;
        l++;
        r--;
    }
    return 1;
}

void generate(int index, char *s, char current[][MAXN], int curSize, void (*callback)(char current[][MAXN], int curSize)) {
    int n = strlen(s);
    if (index == n) {
        callback(current, curSize);
        return;
    }
    for (int end = index; end < n; end++) {
        if (isPalindrome(s, index, end)) {
            int len = end - index + 1;
            strncpy(current[curSize], s + index, len);
            current[curSize][len] = '\0';
            generate(end + 1, s, current, curSize + 1, callback);
        }
    }
}

void printPartition(char current[][MAXN], int curSize) {
    for (int i = 0; i < curSize; i++) {
        printf("%s", current[i]);
        if (i < curSize - 1) printf(" ");
    }
    printf("\n");
}

void partitionString(char *inputString) {
    char current[MAXN][MAXN];
    generate(0, inputString, current, 0, printPartition);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char inputString[MAXN];
        scanf("%s", inputString);
        partitionString(inputString);
    }
    return 0;
}

