import java.util.*;
public class Main {
    public static boolean isPalindrome(String s, int l, int r) {
        while (l < r) {
            if (s.charAt(l) != s.charAt(r)) return false;
            l++;
            r--;
        }
        return true;
    }

    public static void generate(int index, String s, List<String> path, List<List<String>> result) {
        if (index == s.length()) {
            result.add(new ArrayList<>(path));
            return;
        }
        for (int end = index; end < s.length(); end++) {
            if (isPalindrome(s, index, end)) {
                path.add(s.substring(index, end + 1));
                generate(end + 1, s, path, result);
                path.remove(path.size() - 1);
            }
        }
    }

    public static List<List<String>> partitionString(String inputString) {
        List<List<String>> result = new ArrayList<>();
        List<String> path = new ArrayList<>();
        generate(0, inputString, path, result);
        return result;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine();
        while (T-- > 0) {
            String inputString = sc.nextLine();
            List<List<String>> result = partitionString(inputString);
            for (List<String> partition : result) {
                for (String str : partition) {
                    System.out.print(str + " ");
                }
                System.out.println();
            }
        }
    }
}

