def is_palindrome(s, l, r):
    while l < r:
        if s[l] != s[r]:
            return False
        l += 1
        r -= 1
    return True

def backtrack(index, s, path, result):
    if index == len(s):
        result.append(path[:])
        return
    for end in range(index, len(s)):
        if is_palindrome(s, index, end):
            path.append(s[index:end + 1])
            backtrack(end + 1, s, path, result)
            path.pop()

def partition_string(input_string):
    result = []
    backtrack(0, input_string, [], result)
    return result

t = int(input())
for _ in range(t):
    input_string = input()
    result = partition_string(input_string)
    for partition in result:
        print(' '.join(partition))

