function isPalindrome(s, l, r) {
    while (l < r) {
        if (s[l] !== s[r]) return false;
        l++;
        r--;
    }
    return true;
}

function backtrack(index, s, path, result) {
    if (index === s.length) {
        result.push([...path]);
        return;
    }
    for (let end = index; end < s.length; end++) {
        if (isPalindrome(s, index, end)) {
            path.push(s.substring(index, end + 1));
            backtrack(end + 1, s, path, result);
            path.pop();
        }
    }
}

function partitionString(inputString) {
    const result = [];
    backtrack(0, inputString, [], result);
    return result;
}

